/**
 * ManagePlayersPanel — Assign party characters to controllers for co-op.
 *
 * Layout (desktop/tablet landscape):
 *   [MANAGE PLAYERS]                    [Close X]
 *   ─────────────────────────────────────────────
 *   Player 1 (WASD + Mouse)
 *   Character: [Dropdown ▼]             [Navigator]
 *   ...× 4 rows...
 *   ─────────────────────────────────────────────
 *   [Auto-Assign]                       [Confirm]
 *
 * On mobile portrait each player row stacks into a single-column card.
 *
 * Gracefully degrades when CoopSystem is not yet loaded — assignments
 * are stored in a local map and Auto-Assign does a simple random shuffle.
 *
 * Opened/toggled via Tab key (see main.js) or window.__managePlayersPanel.
 *
 * @module ManagePlayersPanel
 */

import { UIPanel } from './UIPanel.js';
import DebugLog from '../debug/DebugLog.js';
import EventBus from '../core/EventBus.js';

// ─── Style injection ──────────────────────────────────────────────────────────

