// ─── Player configuration ─────────────────────────────────────────────────────

/** Static input-label text per player index (0-based). */
const PLAYER_INPUT_LABELS = [
  'WASD + Mouse',
  'Arrows + Gamepad 2',
  'Gamepad 3',
  'Gamepad 4',
];

// ─── Panel class ──────────────────────────────────────────────────────────────

class ManagePlayersPanelClass extends UIPanel {
  constructor() {
    super('panel-manage-players', {
      trapFocus: true,
      zLayer: 'modal',
    });

    /**
     * Working copy of assignments: playerIndex (0-based) => characterId | null.
     * @type {Map<number, string|null>}
     */
    this._assignments = new Map([
      [0, null],
      [1, null],
      [2, null],
      [3, null],
    ]);

    /** Navigator player index (0-based), or null if none assigned. */
    this._navigatorIndex = null;

    /** Cached party characters from CharacterSystem (or placeholders). */
    this._partyChars = [];

    /** Whether CoopSystem was found on last open. */
    this._coopLoaded = false;

    this._panelInitialized = false;
  }

  // ─── Init ────────────────────────────────────────────────────────────────

  init() {
    if (this._panelInitialized) return;
    this._panelInitialized = true;
    injectStyles();
    DebugLog.info('[ui] ManagePlayersPanel initialized');
  }

  // ─── UIPanel overrides ───────────────────────────────────────────────────

  /**
   * Provide initial HTML skeleton that UIPanel._create() will use.
   * The body content is replaced each time the panel opens via updateContent().
   * @returns {string}
   */
  _buildHTML() {
    return `
      <div class="mp-header">
        <span class="mp-title">Manage Players</span>
        <button class="mp-close" aria-label="Close panel" tabindex="0">&#x2715;</button>
      </div>
      <div class="mp-body" id="mp-body-inner">
        <p class="mp-loading">Loading...</p>
      </div>
      <div class="mp-footer">
        <button class="mp-btn" id="mp-btn-auto" tabindex="0">Auto-Assign</button>
        <button class="mp-btn mp-btn--primary" id="mp-btn-confirm" tabindex="0">Confirm</button>
      </div>
    `;
  }

  /**
   * Called by UIPanel.show() every time the panel is opened.
   * Syncs from CoopSystem, loads characters, rebuilds body.
   */
  updateContent() {
    this._syncFromCoopSystem();
    this._loadPartyChars();
    this._renderBody();
    this._bindFooterButtons();
    this._bindCloseButton();
    this._refreshFocusables();
  }

  // ─── Data helpers ────────────────────────────────────────────────────────

  /**
   * Pull current assignments from CoopSystem if available.
   * Keeps this._assignments intact if CoopSystem is not found.
   */
  _syncFromCoopSystem() {
    const cs = this._getCoopSystem();
    if (!cs) {
      this._coopLoaded = false;
      return;
    }

    this._coopLoaded = true;

    try {
      const existing = typeof cs.getAssignments === 'function' ? cs.getAssignments() : null;
      if (existing) {
        const entries = existing instanceof Map
          ? existing.entries()
          : Object.entries(existing);
        for (const [k, v] of entries) {
          const idx = parseInt(k, 10);
          if (!Number.isNaN(idx) && idx >= 0 && idx < 4) {
            this._assignments.set(idx, v ?? null);
          }
        }
      }
    } catch (err) {
      DebugLog.warn(`[ui] ManagePlayersPanel: getAssignments error — ${err.message}`);
    }

    try {
      if (typeof cs.getNavigatorIndex === 'function') {
        const nav = cs.getNavigatorIndex();
        this._navigatorIndex = typeof nav === 'number' ? nav : null;
      }
    } catch (err) {
      DebugLog.warn(`[ui] ManagePlayersPanel: getNavigatorIndex error — ${err.message}`);
    }
  }

  /**
   * Load party characters. Falls back to placeholder data when CharacterSystem
   * is unavailable so the panel renders correctly for testing.
   */
  _loadPartyChars() {
    try {
      const CharSys = window.__characterSystem ?? null;
      if (CharSys && typeof CharSys.getAll === 'function') {
        this._partyChars = CharSys.getAll().filter(c => c.isHero).slice(0, 4);
        return;
      }
    } catch (err) {
      DebugLog.warn(`[ui] ManagePlayersPanel: CharacterSystem load error — ${err.message}`);
    }

    // Fallback placeholder list for pre-data milestones
    this._partyChars = [
      { id: 'char_sigrid', name: 'Sigrid Flamehair' },
      { id: 'char_bjorn',  name: 'Bjorn Ironshield'  },
      { id: 'char_astrid', name: 'Astrid Skywarden'  },
      { id: 'char_ragnar', name: 'Ragnar Coldaxe'    },
    ];
  }

  /**
   * @returns {object|null} CoopSystem singleton exposed on window, or null.
   */
  _getCoopSystem() {
    return window.__coopSystem ?? null;
  }

  // ─── Render ──────────────────────────────────────────────────────────────

  _renderBody() {
    const bodyEl = this.el.querySelector('#mp-body-inner');
    if (!bodyEl) return;

    const rowsHTML = [0, 1, 2, 3].map(i => this._buildPlayerRowHTML(i)).join('');
    bodyEl.innerHTML = rowsHTML
      + (!this._coopLoaded
        ? `<p class="mp-loading">Co-op system loading... Auto-Assign uses random order.</p>`
        : '');

    this._bindPlayerRows();
  }

  /**
   * Build the HTML for one player row.
   * @param {number} playerIndex — 0-based
   * @returns {string}
   */
  _buildPlayerRowHTML(playerIndex) {
    const playerNum    = playerIndex + 1;
    const inputLabel   = PLAYER_INPUT_LABELS[playerIndex] ?? `Gamepad ${playerNum}`;
    const assignedId   = this._assignments.get(playerIndex) ?? null;
    const isNavigator  = this._navigatorIndex === playerIndex;
    const hasCharacter = Boolean(assignedId);

    const noneOption = `<option value="" ${!assignedId ? 'selected' : ''}>None</option>`;
    const charOptions = this._partyChars.map(c => {
      const sel = assignedId === c.id ? 'selected' : '';
      return `<option value="${this._esc(c.id)}" ${sel}>${this._esc(c.name)}</option>`;
    }).join('');

    return `
      <div class="mp-player-card" data-player-index="${playerIndex}">
        <div class="mp-player-info">
          <div class="mp-player-number">Player ${playerNum}</div>
          <div class="mp-player-input-label">${this._esc(inputLabel)}</div>
        </div>

        <div class="mp-char-select-wrap">
          <select
            class="mp-char-select"
            id="mp-select-p${playerIndex}"
            data-player-index="${playerIndex}"
            aria-label="Character for Player ${playerNum}"
            tabindex="0"
          >${noneOption}${charOptions}</select>
          <div class="mp-error" id="mp-error-p${playerIndex}" aria-live="polite" role="alert"></div>
        </div>

        <div class="mp-navigator-wrap">
          <div class="mp-navigator-label">Navigator</div>
          <button
            class="mp-navigator-btn${isNavigator ? ' is-navigator' : ''}"
            id="mp-nav-p${playerIndex}"
            data-player-index="${playerIndex}"
            aria-label="Set Player ${playerNum} as Navigator"
            aria-pressed="${isNavigator}"
            ${hasCharacter ? '' : 'disabled'}
            tabindex="0"
          >&#9906;</button>
        </div>
      </div>
    `;
  }

  // ─── Event binding ────────────────────────────────────────────────────────

  _bindPlayerRows() {
    this.el.querySelectorAll('.mp-char-select').forEach(sel => {
      sel.addEventListener('change', (e) => {
        const idx   = parseInt(e.target.dataset.playerIndex, 10);
        const charId = e.target.value || null;
        this._handleCharacterChange(idx, charId);
      });
    });

    this.el.querySelectorAll('.mp-navigator-btn').forEach(btn => {
      btn.addEventListener('click', (e) => {
        const idx = parseInt(e.currentTarget.dataset.playerIndex, 10);
        this._handleNavigatorToggle(idx);
      });
    });
  }

  _bindFooterButtons() {
    const autoBtn = this.el.querySelector('#mp-btn-auto');
    if (autoBtn) autoBtn.addEventListener('click', () => this._handleAutoAssign());

    const confirmBtn = this.el.querySelector('#mp-btn-confirm');
    if (confirmBtn) confirmBtn.addEventListener('click', () => this._handleConfirm());
  }

  _bindCloseButton() {
    const closeBtn = this.el.querySelector('.mp-close');
    if (closeBtn) closeBtn.addEventListener('click', () => this.hide());
  }

  // ─── Interaction handlers ─────────────────────────────────────────────────

  /**
   * Handle character selection from a dropdown.
   * Blocks duplicate assignments and shows an inline error if attempted.
   * @param {number} playerIndex
   * @param {string|null} charId
   */
  _handleCharacterChange(playerIndex, charId) {
    // Guard: reject duplicate assignments
    if (charId) {
      for (const [otherIdx, existingId] of this._assignments) {
        if (otherIdx !== playerIndex && existingId === charId) {
          this._showError(playerIndex, 'Character already assigned to another player.');
          // Revert the select element visually
          const sel = this.el.querySelector(`#mp-select-p${playerIndex}`);
          if (sel) sel.value = this._assignments.get(playerIndex) ?? '';
          return;
        }
      }
    }

    this._clearError(playerIndex);
    this._assignments.set(playerIndex, charId);

    // If the player lost their character and was Navigator, clear Navigator
    if (!charId && this._navigatorIndex === playerIndex) {
      this._navigatorIndex = null;
      this._refreshNavigatorButtons();
    }

    // Update Navigator button enabled state
    const navBtn = this.el.querySelector(`#mp-nav-p${playerIndex}`);
    if (navBtn) {
      if (charId) {
        navBtn.removeAttribute('disabled');
      } else {
        navBtn.setAttribute('disabled', '');
        navBtn.classList.remove('is-navigator');
        navBtn.setAttribute('aria-pressed', 'false');
      }
    }

    DebugLog.info(`[ui] ManagePlayersPanel: P${playerIndex + 1} char="${charId ?? 'None'}"`);
  }

  /**
   * Toggle the Navigator designation for a player.
   * Selecting a new Navigator automatically deselects the previous one.
   * @param {number} playerIndex
   */
  _handleNavigatorToggle(playerIndex) {
    if (!this._assignments.get(playerIndex)) return;

    // Clicking the current Navigator deselects; clicking another reassigns
    this._navigatorIndex = this._navigatorIndex === playerIndex ? null : playerIndex;
    this._refreshNavigatorButtons();

    const label = this._navigatorIndex != null ? `P${this._navigatorIndex + 1}` : 'None';
    DebugLog.info(`[ui] ManagePlayersPanel: Navigator => ${label}`);
  }

  /**
   * Auto-assign characters to players.
   * Delegates to CoopSystem.autoAssign() when available; falls back to a
   * simple randomised sequential assignment.
   */
  _handleAutoAssign() {
    const cs = this._getCoopSystem();

    if (cs && typeof cs.autoAssign === 'function') {
      try {
        cs.autoAssign();
        this._syncFromCoopSystem();
        DebugLog.info('[ui] ManagePlayersPanel: CoopSystem.autoAssign() called');
      } catch (err) {
        DebugLog.warn(`[ui] ManagePlayersPanel: CoopSystem.autoAssign error — ${err.message}`);
        this._fallbackAutoAssign();
      }
    } else {
      this._fallbackAutoAssign();
    }

    this._renderBody();
    this._bindFooterButtons();
    this._bindCloseButton();
    this._refreshFocusables();
  }

  /**
   * Fallback auto-assign: randomly shuffle party characters across players.
   * Sets P1 (or first available) as Navigator.
   */
  _fallbackAutoAssign() {
    const chars = [...this._partyChars];
    // Fisher-Yates shuffle
    for (let i = chars.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [chars[i], chars[j]] = [chars[j], chars[i]];
    }

    this._assignments.clear();
    for (let i = 0; i < 4; i++) {
      this._assignments.set(i, chars[i]?.id ?? null);
    }

    // Assign Navigator to the first player who has a character
    this._navigatorIndex = null;
    for (let i = 0; i < 4; i++) {
      if (this._assignments.get(i)) {
        this._navigatorIndex = i;
        break;
      }
    }

    DebugLog.info('[ui] ManagePlayersPanel: fallback auto-assign applied');
  }

  /**
   * Validate assignments, save to CoopSystem, emit confirmation event, close.
   */
  _handleConfirm() {
    // Clear any stale errors
    for (let i = 0; i < 4; i++) this._clearError(i);

    // Validate for duplicates (belt-and-suspenders — should not be possible
    // via normal UI, but protects against programmatic manipulation)
    const seen = new Set();
    let hasError = false;
    for (const [idx, charId] of this._assignments) {
      if (charId && seen.has(charId)) {
        this._showError(idx, 'Duplicate character assignment.');
        hasError = true;
      } else if (charId) {
        seen.add(charId);
      }
    }
    if (hasError) return;

    // Persist to CoopSystem
    const cs = this._getCoopSystem();
    if (cs) {
      try {
        if (typeof cs.assignCharacter === 'function') {
          for (const [playerIndex, charId] of this._assignments) {
            cs.assignCharacter(playerIndex, charId);
          }
        }
        if (this._navigatorIndex != null && typeof cs.setNavigator === 'function') {
          cs.setNavigator(this._navigatorIndex);
        }
        DebugLog.info('[ui] ManagePlayersPanel: assignments saved to CoopSystem');
      } catch (err) {
        DebugLog.warn(`[ui] ManagePlayersPanel: CoopSystem save error — ${err.message}`);
      }
    }

    // Broadcast confirmed assignments
    try {
      EventBus.emit('coop:assignments_confirmed', {
        assignments: Object.fromEntries(this._assignments),
        navigatorIndex: this._navigatorIndex,
      });
    } catch (_) { /* EventBus might not be available in all test contexts */ }

    DebugLog.info('[ui] ManagePlayersPanel: confirmed, closing');
    this.hide();
  }

  // ─── UI helpers ──────────────────────────────────────────────────────────

  /**
   * Redraw all Navigator buttons to match this._navigatorIndex.
   * Used for lightweight in-place updates (no full body rebuild needed).
   */
  _refreshNavigatorButtons() {
    for (let i = 0; i < 4; i++) {
      const btn = this.el.querySelector(`#mp-nav-p${i}`);
      if (!btn) continue;
      const isNav = this._navigatorIndex === i;
      btn.classList.toggle('is-navigator', isNav);
      btn.setAttribute('aria-pressed', String(isNav));
    }
  }

  /**
   * @param {number} playerIndex
   * @param {string} message
   */
  _showError(playerIndex, message) {
    const el = this.el.querySelector(`#mp-error-p${playerIndex}`);
    if (el) el.textContent = message;
  }

  /**
   * @param {number} playerIndex
   */
  _clearError(playerIndex) {
    const el = this.el.querySelector(`#mp-error-p${playerIndex}`);
    if (el) el.textContent = '';
  }

  /**
   * HTML-escape a value for safe injection into innerHTML.
   * @param {unknown} val
   * @returns {string}
   */
  _esc(val) {
    return String(val ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }
}

// ─── Singleton facade ─────────────────────────────────────────────────────────

/** @type {ManagePlayersPanelClass|null} */
let _instance = null;

const ManagePlayersPanel = {
  /**
   * Create the panel and inject styles.
   * Safe to call multiple times — idempotent.
   */
  init() {
    if (!_instance) {
      _instance = new ManagePlayersPanelClass();
    }
    _instance.init();
  },

  /** Show the panel, optionally passing data. */
  show(data) {
    _instance?.show(data);
  },

  /** Hide the panel. */
  hide() {
    _instance?.hide();
  },

  /**
   * Toggle visibility.
   * @param {*} [data]
   */
  toggle(data) {
    _instance?.toggle(data);
  },

  /** @returns {boolean} */
  isVisible() {
    return _instance?.isVisible() ?? false;
  },

  /** Direct access to the underlying UIPanel instance (for tests). */
  get panel() {
    return _instance;
  },
};

export default ManagePlayersPanel;
