/**
 * AchievementSystem — Tracks and awards Spellroads achievements.
 *
 * Achievements are defined in /src/data/achievements.json.
 * Progress is saved/loaded via SaveSystem as part of the main snapshot.
 * Toast notifications are shown when an achievement is unlocked.
 */

import DebugLog from '../debug/DebugLog.js';
import achievementsData from '../data/achievements.json';

const AchievementSystem = {
  /** @type {object[]} All achievement definitions */
  _defs: achievementsData,

  /**
   * Progress map: achievementId → { count: number, unlocked: boolean, unlockedAt: number|null }
   * @type {Object<string, object>}
   */
  _progress: {},

  /** @type {Function|null} Optional callback when achievement unlocked */
  onUnlock: null,

  // ── Init ───────────────────────────────────────────────────────────────────

  init() {
    this._progress = {};
    for (const def of this._defs) {
      this._progress[def.id] = { count: 0, unlocked: false, unlockedAt: null };
    }
    DebugLog.info(`[achievement] AchievementSystem initialized — ${this._defs.length} achievements`);
  },

  // ── Trigger ────────────────────────────────────────────────────────────────

  /**
   * Notify the achievement system that an event occurred.
   * @param {string} trigger — Event type (e.g. 'quest_complete', 'combat_victory')
   * @param {object} [ctx={}] — Context data (questId, enemyId, tier, etc.)
   */
  trigger(triggerName, ctx = {}) {
    for (const def of this._defs) {
      if (def.trigger !== triggerName) continue;

      const prog = this._progress[def.id];
      if (prog.unlocked) continue;

      let shouldCount = false;

      // Match by context specificity
      if (def.questId)   shouldCount = ctx.questId   === def.questId;
      else if (def.enemyId)   shouldCount = ctx.enemyId   === def.enemyId;
      else if (def.enemyType) shouldCount = ctx.enemyType === def.enemyType;
      else if (def.tier)      shouldCount = ctx.tier      === def.tier;
      else if (def.vehicleId) shouldCount = ctx.vehicleId === def.vehicleId;
      else                    shouldCount = true; // generic threshold

      if (!shouldCount) continue;

      prog.count += (ctx.amount ?? 1);

      const threshold = def.threshold ?? 1;
      if (prog.count >= threshold) {
        prog.unlocked   = true;
        prog.unlockedAt = Date.now();
        this._onUnlocked(def);
      }
    }
  },

  _onUnlocked(def) {
    DebugLog.event(`[achievement] Unlocked: ${def.id} — ${def.name}`);

    // Show toast notification
    try {
      import('../ui/Toast.js').then(m => {
        m.default.show(`Achievement unlocked: ${def.name}`, {
          type: 'success',
          duration: 3500,
        });
      });
    } catch (_) {}

    if (typeof this.onUnlock === 'function') {
      this.onUnlock(def);
    }
  },

  // ── Queries ────────────────────────────────────────────────────────────────

  /** Get all achievement definitions with current progress merged in. */
  getAll() {
    return this._defs.map(def => ({
      ...def,
      progress: this._progress[def.id] ?? { count: 0, unlocked: false, unlockedAt: null },
    }));
  },

  /** Get only unlocked achievements. */
  getUnlocked() {
    return this.getAll().filter(a => a.progress.unlocked);
  },

  /** Get achievements by category. */
  getByCategory(category) {
    return this.getAll().filter(a => a.category === category);
  },

  /** Get progress object for serialization (SaveSystem). */
  getProgress() {
    return JSON.parse(JSON.stringify(this._progress));
  },

  /** Restore progress from SaveSystem. */
  restoreProgress(saved) {
    for (const [id, prog] of Object.entries(saved)) {
      if (this._progress[id]) {
        this._progress[id] = prog;
      }
    }
    DebugLog.info(`[achievement] Progress restored — ${this.getUnlocked().length} unlocked`);
  },

  /** Unlock count summary for debug. */
  getSummary() {
    const total   = this._defs.length;
    const unlocked = this.getUnlocked().length;
    return { total, unlocked, percentage: Math.round(unlocked / total * 100) };
  },
};

export default AchievementSystem;
