// ─── TownMenuPanel ────────────────────────────────────────────────────────────

const TownMenuPanel = {
  /** @type {HTMLElement|null} */
  _el: null,

  /** @type {string} Currently active service tab */
  _activeService: null,

  /** @type {object|null} Current town data */
  _townData: null,

  /** @type {boolean} */
  _visible: false,

  // ─── Public API ─────────────────────────────────────────────────────────

  /**
   * Open the town menu for a specific town.
   * @param {object} townData
   * @param {string} townData.name — Display name
   * @param {string} [townData.type] — Town type label (e.g. 'trading_post')
   * @param {string[]} [townData.services] — Available service IDs
   */
  open(townData = {}) {
    injectStyles();

    this._townData = {
      name:     townData.name     ?? 'Town',
      type:     townData.type     ?? 'settlement',
      services: townData.services ?? Object.keys(SERVICE_META),
    };

    if (!this._el) this._buildDOM();

    this._renderHeader();
    this._renderSidebar();

    // Select first available service
    const firstService = SERVICE_ORDER.find(s => this._townData.services.includes(s))
      ?? this._townData.services[0];
    this._selectService(firstService);

    this._el.classList.add('tmp-visible');
    this._visible = true;

    DebugLog.info(`[debug] TownMenuPanel opened: ${this._townData.name}`);
    EventBus.emit('town:opened', { name: this._townData.name });

    // Focus first interactive element
    requestAnimationFrame(() => {
      this._el?.querySelector('.tmp-service-btn:not(:disabled)')?.focus();
    });
  },

  /**
   * Close the town menu.
   */
  close() {
    if (!this._visible) return;
    this._el?.classList.remove('tmp-visible');
    this._visible = false;
    this._townData = null;
    this._activeService = null;

    DebugLog.info('[debug] TownMenuPanel closed');
    EventBus.emit('town:closed', {});
  },

  /** @returns {boolean} */
  isOpen() { return this._visible; },

  // ─── DOM construction ────────────────────────────────────────────────────

  _buildDOM() {
    document.getElementById('town-menu-panel')?.remove();

    const el = document.createElement('div');
    el.id = 'town-menu-panel';
    el.setAttribute('role', 'dialog');
    el.setAttribute('aria-modal', 'true');
    el.setAttribute('aria-label', 'Town Menu');

    el.innerHTML = `
      <div class="tmp-header" id="tmp-header"></div>
      <div class="tmp-body">
        <nav class="tmp-sidebar" id="tmp-sidebar" aria-label="Town services"></nav>
        <div class="tmp-content" id="tmp-content" role="region" aria-live="polite"></div>
      </div>
    `;

    document.body.appendChild(el);
    this._el = el;

    // Close on Escape
    el.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') { e.stopPropagation(); this.close(); }
    });
  },

  // ─── Header ──────────────────────────────────────────────────────────────

  _renderHeader() {
    const header = this._el.querySelector('#tmp-header');
    const gold   = WorldState.partyGold ?? 0;
    const typeLabel = (this._townData.type ?? 'settlement')
      .replace(/_/g, ' ')
      .replace(/\b\w/g, c => c.toUpperCase());

    header.innerHTML = `
      <div class="tmp-header-left">
        <div class="tmp-town-name">${this._escHtml(this._townData.name)}</div>
        <div class="tmp-town-type">${this._escHtml(typeLabel)}</div>
      </div>
      <div class="tmp-header-right">
        <span class="tmp-gold-display">
          <span class="tmp-gold-icon">&#9670;</span>
          <span id="tmp-gold-value">${gold}g</span>
        </span>
        <button class="tmp-close-btn" aria-label="Leave town" title="Leave town (Esc)">&#10005;</button>
      </div>
    `;

    header.querySelector('.tmp-close-btn').addEventListener('click', () => this.close());
  },

  /** Refresh only the gold display (called after purchases). */
  _refreshGold() {
    const el = this._el?.querySelector('#tmp-gold-value');
    if (el) el.textContent = `${WorldState.partyGold ?? 0}g`;
  },

  // ─── Sidebar ─────────────────────────────────────────────────────────────

  _renderSidebar() {
    const sidebar = this._el.querySelector('#tmp-sidebar');
    sidebar.innerHTML = '';

    const servicesLabel = document.createElement('div');
    servicesLabel.className = 'tmp-sidebar-label';
    servicesLabel.textContent = 'Services';
    sidebar.appendChild(servicesLabel);

    for (const serviceId of SERVICE_ORDER) {
      if (!this._townData.services.includes(serviceId)) continue;
      const meta = SERVICE_META[serviceId];
      if (!meta) continue;

      const btn = document.createElement('button');
      btn.className = 'tmp-service-btn';
      btn.dataset.service = serviceId;
      btn.setAttribute('aria-pressed', 'false');
      btn.innerHTML = `<span class="tmp-service-icon">${meta.icon}</span>${this._escHtml(meta.label)}`;
      btn.addEventListener('click', () => this._selectService(serviceId));
      sidebar.appendChild(btn);
    }

    // Leave Town at bottom
    const leaveContainer = document.createElement('div');
    leaveContainer.className = 'tmp-leave-btn';

    const leaveBtn = document.createElement('button');
    leaveBtn.className = 'tmp-service-btn';
    leaveBtn.innerHTML = '<span class="tmp-service-icon">&#8594;</span>Leave Town';
    leaveBtn.addEventListener('click', () => this.close());
    leaveContainer.appendChild(leaveBtn);
    sidebar.appendChild(leaveContainer);
  },

  // ─── Service selection ────────────────────────────────────────────────────

  _selectService(serviceId) {
    this._activeService = serviceId;

    // Update sidebar active state
    this._el.querySelectorAll('.tmp-service-btn[data-service]').forEach(btn => {
      const active = btn.dataset.service === serviceId;
      btn.classList.toggle('active', active);
      btn.setAttribute('aria-pressed', active ? 'true' : 'false');
    });

    // Render content
    const content = this._el.querySelector('#tmp-content');
    content.innerHTML = '';

    switch (serviceId) {
      case 'blacksmith':    this._renderBlacksmith(content);   break;
      case 'general_store': this._renderGeneralStore(content); break;
      case 'inn':           this._renderInn(content);          break;
      case 'tavern':        this._renderTavern(content);       break;
      case 'temple':        this._renderTemple(content);       break;
      case 'party':         this._renderPartyManagement(content); break;
      default:
        content.innerHTML = `<p style="color:#706050;padding:20px">This service is not available here.</p>`;
    }
  },

  // ─── Section renderers ────────────────────────────────────────────────────

  _renderBlacksmith(container) {
    const items = [
      { id: 'iron_sword',    name: 'Iron Sword',      desc: 'A dependable one-handed sword. Damage +4.',  price: 80  },
      { id: 'battle_axe',   name: 'Battle Axe',       desc: 'Heavy two-handed axe. Damage +6.',          price: 120 },
      { id: 'short_bow',    name: 'Short Bow',         desc: 'Compact ranged weapon. Range 4.',           price: 75  },
      { id: 'iron_shield',  name: 'Iron Shield',       desc: 'Grants +2 armor. One hand.',                price: 60  },
      { id: 'leather_vest', name: 'Leather Vest',      desc: 'Light armor. +1 armor, no speed penalty.',  price: 55  },
      { id: 'chain_shirt',  name: 'Chain Shirt',       desc: 'Medium armor. +3 armor.',                   price: 140 },
      { id: 'iron_helm',    name: 'Iron Helm',         desc: '+1 armor. Protects the head.',              price: 45  },
      { id: 'repair_kit',   name: 'Repair Kit',        desc: 'Restore 10 durability to one item.',        price: 30  },
    ];

    this._renderShopItems(container, 'Blacksmith', SERVICE_META.blacksmith.icon, items,
      'Heavy weapons and protective gear, forged on-site.');
  },

  _renderGeneralStore(container) {
    const items = [
      { id: 'health_potion_small',  name: 'Small Health Potion', desc: 'Restores 15 HP.',           price: 20  },
      { id: 'health_potion_medium', name: 'Health Potion',        desc: 'Restores 35 HP.',           price: 40  },
      { id: 'antidote',             name: 'Antidote',             desc: 'Cures Poisoned status.',    price: 25  },
      { id: 'torch',                name: 'Torch (x5)',           desc: 'Provides light in caves.',  price: 10  },
      { id: 'rations_standard',     name: 'Travel Rations (x5)', desc: '+10 ration points.',        price: 15  },
      { id: 'rope',                 name: 'Rope (15m)',           desc: 'Useful in many situations.',price: 12  },
      { id: 'bandage',              name: 'Bandage',              desc: 'Stops Bleeding status.',    price: 8   },
      { id: 'camping_kit',          name: 'Camping Kit',          desc: '+2 rest bonus to next camp.',price: 50 },
    ];

    this._renderShopItems(container, 'General Store', SERVICE_META.general_store.icon, items,
      'Supplies, consumables, and everyday goods for the road.');
  },

  _renderShopItems(container, title, icon, items, desc) {
    container.innerHTML = `
      <div class="tmp-section-title">${icon} ${this._escHtml(title)}</div>
      <div class="tmp-section-desc">${this._escHtml(desc)}</div>
      <div class="tmp-item-list" id="tmp-shop-list"></div>
    `;

    const list = container.querySelector('#tmp-shop-list');
    for (const item of items) {
      const row = document.createElement('div');
      row.className = 'tmp-item-row';
      row.innerHTML = `
        <div class="tmp-item-info">
          <div class="tmp-item-name">${this._escHtml(item.name)}</div>
          <div class="tmp-item-desc">${this._escHtml(item.desc)}</div>
        </div>
        <div class="tmp-item-actions">
          <span class="tmp-item-price">${item.price}g</span>
          <button class="tmp-action-btn" data-action="buy" data-item="${item.id}" data-price="${item.price}">Buy</button>
        </div>
      `;
      list.appendChild(row);
    }

    list.addEventListener('click', (e) => {
      const btn = e.target.closest('[data-action="buy"]');
      if (!btn) return;
      const price  = parseInt(btn.dataset.price, 10);
      const itemId = btn.dataset.item;
      this._handleBuy(itemId, price, btn);
    });
  },

  _handleBuy(itemId, price, btn) {
    const gold = WorldState.partyGold ?? 0;
    if (gold < price) {
      this._toast('Not enough gold.', 'error');
      return;
    }

    WorldState.partyGold = gold - price;
    this._refreshGold();

    // Give item if inventory system is ready
    if (window.__inventoryManager?.addItem) {
      window.__inventoryManager.addItem(null, itemId, 1);
    }

    DebugLog.event(`[item] Purchased ${itemId} for ${price}g`);
    this._toast(`Purchased: ${itemId.replace(/_/g, ' ')}`, 'success');
  },

  _renderInn(container) {
    const innName   = INN_NAMES[Math.floor(Math.random() * INN_NAMES.length)];
    const partySize = (WorldState.party?.length ?? 1);
    const costPerPerson = 8;
    const totalCost = partySize * costPerPerson;

    container.innerHTML = `
      <div class="tmp-section-title">${SERVICE_META.inn.icon} ${this._escHtml(innName)}</div>
      <div class="tmp-section-desc">Rest the night, restore HP and remove minor status effects. Shared room rate.</div>
      <div class="tmp-confirm-box">
        <div class="tmp-confirm-title">Rest for the Night</div>
        <div class="tmp-confirm-body">
          Party size: ${partySize} person${partySize !== 1 ? 's' : ''}<br>
          Cost: ${costPerPerson}g per person &mdash; <strong style="color:#d4aa40">${totalCost}g total</strong><br><br>
          Everyone will recover to full HP and Stamina. Status effects <em>Exhausted</em>, <em>Chilled</em>,
          and <em>Minor Wounds</em> will be cleared.
        </div>
        <div class="tmp-confirm-actions">
          <button class="tmp-action-btn" id="tmp-inn-rest">Rest (${totalCost}g)</button>
          <button class="tmp-action-btn" id="tmp-inn-cancel" style="background:rgba(80,40,10,0.2);border-color:rgba(160,100,30,0.3);color:#907860">Cancel</button>
        </div>
      </div>
    `;

    container.querySelector('#tmp-inn-rest').addEventListener('click', () => {
      const gold = WorldState.partyGold ?? 0;
      if (gold < totalCost) { this._toast('Not enough gold.', 'error'); return; }
      WorldState.partyGold = gold - totalCost;
      this._refreshGold();
      EventBus.emit('party:rest', { type: 'inn', quality: 'full' });
      DebugLog.event(`[party] Party rested at inn "${innName}"; cost=${totalCost}g`);
      this._toast('The party rests well. All HP restored.', 'success');
    });

    container.querySelector('#tmp-inn-cancel').addEventListener('click', () => {
      this._toast('Perhaps another night.', 'info');
    });
  },

  _renderTavern(container) {
    container.innerHTML = `
      <div class="tmp-section-title">${SERVICE_META.tavern.icon} The Tavern</div>
      <div class="tmp-section-desc">Hire mercenaries, hear local rumors, and find work.</div>
    `;

    // Rumors section
    const rumorTitle = document.createElement('div');
    rumorTitle.style.cssText = 'font-size:0.78rem;text-transform:uppercase;letter-spacing:0.1em;color:#605040;margin-top:8px;';
    rumorTitle.textContent = 'Rumors Heard Tonight';
    container.appendChild(rumorTitle);

    const rumorCount = 2 + Math.floor(Math.random() * 2);
    const shuffled   = [...TAVERN_RUMORS].sort(() => Math.random() - 0.5).slice(0, rumorCount);
    for (const rumor of shuffled) {
      const box = document.createElement('div');
      box.className = 'tmp-rumor-box';
      box.innerHTML = `"${this._escHtml(rumor)}" <span class="tmp-rumor-source">— overheard at the bar</span>`;
      container.appendChild(box);
    }

    // Mercenaries section
    const mercTitle = document.createElement('div');
    mercTitle.style.cssText = 'font-size:0.78rem;text-transform:uppercase;letter-spacing:0.1em;color:#605040;margin-top:18px;';
    mercTitle.textContent = 'Mercenaries for Hire';
    container.appendChild(mercTitle);

    // Load hireable NPCs
    const npcs = this._getHireableNPCs();
    const available = npcs.slice(0, 4); // Show up to 4 in tavern

    for (const npc of available) {
      const row = document.createElement('div');
      row.className = 'tmp-merc-row';
      const wagePerDay = npc.wagePerDay ?? 5;
      row.innerHTML = `
        <div>
          <div class="tmp-merc-name">${this._escHtml(npc.name)}</div>
          <div class="tmp-merc-class">${this._escHtml(npc.class ?? 'Fighter')} &mdash; Lv.${npc.baseLevel ?? 1}</div>
          <div style="font-size:0.7rem;color:#706050;margin-top:2px;">${this._escHtml(npc.description ?? '')}</div>
        </div>
        <span class="tmp-merc-wage">${wagePerDay}g/day</span>
        <button class="tmp-action-btn" data-hire="${npc.id}" data-wage="${wagePerDay}">Hire</button>
      `;
      container.appendChild(row);
    }

    if (!available.length) {
      const empty = document.createElement('div');
      empty.style.cssText = 'color:#605040;font-size:0.82rem;padding:12px;';
      empty.textContent = 'No mercenaries are available at this time.';
      container.appendChild(empty);
    }

    container.addEventListener('click', (e) => {
      const btn = e.target.closest('[data-hire]');
      if (!btn) return;
      const npcId    = btn.dataset.hire;
      const wagePerDay = parseInt(btn.dataset.wage, 10);
      EventBus.emit('party:hire_npc', { npcId, wagePerDay });
      DebugLog.event(`[party] Hired mercenary; npcId=${npcId} wage=${wagePerDay}g/day`);
      this._toast(`Mercenary hired. Wage: ${wagePerDay}g/day.`, 'success');
      btn.disabled = true;
    });
  },

  _renderTemple(container) {
    const partySize = WorldState.party?.length ?? 1;

    container.innerHTML = `
      <div class="tmp-section-title">${SERVICE_META.temple.icon} Temple</div>
      <div class="tmp-section-desc">Healing services, status cure, and blessings from the priests.</div>
      <div class="tmp-item-list"></div>
    `;

    const services = [
      {
        id: 'full_heal',
        name: 'Full Party Healing',
        desc: 'Restore all party members to full HP.',
        price: 20 * partySize,
        action: () => {
          EventBus.emit('party:heal', { type: 'full', target: 'all' });
          DebugLog.event('[party] Temple full heal performed');
          this._toast('The priests lay hands on your party. All wounds are healed.', 'success');
        },
      },
      {
        id: 'cure_status',
        name: 'Cure All Status Effects',
        desc: 'Remove Poisoned, Cursed, Bleeding, and all debuffs from the party.',
        price: 15 * partySize,
        action: () => {
          EventBus.emit('party:cure', { target: 'all' });
          DebugLog.event('[party] Temple status cure performed');
          this._toast('Ailments cleansed. The party feels lighter.', 'success');
        },
      },
      {
        id: 'bless',
        name: 'Battle Blessing',
        desc: '+1 to all attack and skill rolls for the next 3 combat encounters.',
        price: 30,
        action: () => {
          EventBus.emit('party:bless', { duration: 3, bonus: 1 });
          DebugLog.event('[party] Temple blessing applied');
          this._toast('The gods grant their favor. The party is blessed.', 'success');
        },
      },
      {
        id: 'resurrect',
        name: 'Resurrect Fallen',
        desc: 'Bring a fallen party member back with 1 HP. Requires a body.',
        price: 200,
        action: () => {
          EventBus.emit('party:resurrect', {});
          DebugLog.event('[party] Temple resurrection performed');
          this._toast('The fallen breathe again. Resurrection complete.', 'success');
        },
      },
    ];

    const list = container.querySelector('.tmp-item-list');
    for (const svc of services) {
      const row = document.createElement('div');
      row.className = 'tmp-item-row';
      row.innerHTML = `
        <div class="tmp-item-info">
          <div class="tmp-item-name">${this._escHtml(svc.name)}</div>
          <div class="tmp-item-desc">${this._escHtml(svc.desc)}</div>
        </div>
        <div class="tmp-item-actions">
          <span class="tmp-item-price">${svc.price}g</span>
          <button class="tmp-action-btn" data-svc="${svc.id}" data-price="${svc.price}">Purchase</button>
        </div>
      `;
      list.appendChild(row);
    }

    list.addEventListener('click', (e) => {
      const btn = e.target.closest('[data-svc]');
      if (!btn) return;
      const price = parseInt(btn.dataset.price, 10);
      const svcId = btn.dataset.svc;
      const gold  = WorldState.partyGold ?? 0;
      if (gold < price) { this._toast('Not enough gold.', 'error'); return; }
      WorldState.partyGold = gold - price;
      this._refreshGold();
      services.find(s => s.id === svcId)?.action?.();
    });
  },

  _renderPartyManagement(container) {
    container.innerHTML = `
      <div class="tmp-section-title">${SERVICE_META.party.icon} Party Management</div>
      <div class="tmp-section-desc">Review your party's status, rearrange formation, and manage equipment.</div>
    `;

    const party = WorldState.party ?? [];

    if (!party.length) {
      const empty = document.createElement('p');
      empty.style.cssText = 'color:#706050;padding:12px;font-size:0.85rem;';
      empty.textContent = 'No party data available yet. Start a new game to create characters.';
      container.appendChild(empty);
      return;
    }

    for (const member of party) {
      const card = document.createElement('div');
      card.className = 'tmp-item-row';
      card.style.flexDirection = 'column';
      card.style.alignItems    = 'flex-start';
      card.style.gap           = '12px';

      const hpPct = member.maxHp > 0
        ? Math.round((member.hp / member.maxHp) * 100)
        : 100;

      card.innerHTML = `
        <div style="display:flex;justify-content:space-between;width:100%;align-items:center;">
          <div>
            <div class="tmp-item-name">${this._escHtml(member.name ?? 'Unknown')}</div>
            <div class="tmp-item-desc">${this._escHtml(member.class ?? '')} &mdash; Level ${member.level ?? 1}</div>
          </div>
          <div style="text-align:right;">
            <div style="font-size:0.78rem;color:#d4aa40;">HP: ${member.hp ?? '?'}/${member.maxHp ?? '?'}</div>
            <div style="font-size:0.7rem;color:#606050;margin-top:2px;">
              <span style="display:inline-block;width:80px;height:6px;background:rgba(80,60,30,0.5);border-radius:3px;overflow:hidden;vertical-align:middle;">
                <span style="display:block;height:100%;width:${hpPct}%;background:${hpPct > 50 ? '#4a8a30' : hpPct > 25 ? '#9a8020' : '#8a3020'};border-radius:3px;"></span>
              </span>
              ${hpPct}%
            </div>
          </div>
        </div>
        <div class="tmp-stat-grid">
          ${this._renderStatCells(member.attributes ?? {})}
        </div>
      `;
      container.appendChild(card);
    }

    // Open full manage players panel button
    const manageBtn = document.createElement('button');
    manageBtn.className = 'tmp-action-btn';
    manageBtn.style.marginTop = '8px';
    manageBtn.textContent = 'Open Full Party Manager';
    manageBtn.addEventListener('click', () => {
      window.__managePlayersPanel?.toggle();
    });
    container.appendChild(manageBtn);
  },

  // ─── Helpers ─────────────────────────────────────────────────────────────

  _renderStatCells(attrs) {
    const stats = ['might', 'agility', 'intellect', 'wisdom', 'endurance', 'presence'];
    return stats.map(s => `
      <div class="tmp-stat-cell">
        <span class="tmp-stat-label">${s.slice(0, 3).toUpperCase()}</span>
        <span class="tmp-stat-value">${attrs[s] ?? '--'}</span>
      </div>
    `).join('');
  },

  _getHireableNPCs() {
    // Try to use loaded data, fall back to a minimal inline sample
    if (window.__hireableNPCs?.length) return window.__hireableNPCs;

    return [
      { id: 'hired_warrior', name: 'Sellsword',       class: 'warrior',  baseLevel: 1, wagePerDay: 5,  description: 'A battle-hardened sellsword who fights for coin.' },
      { id: 'hired_archer',  name: 'Bowman',           class: 'archer',   baseLevel: 1, wagePerDay: 5,  description: 'A skilled archer whose arrows find their mark.' },
      { id: 'hired_mage',    name: 'Wandering Mage',   class: 'mage',     baseLevel: 2, wagePerDay: 8,  description: 'A mage seeking adventure and arcane knowledge.' },
      { id: 'hired_healer',  name: 'Wandering Healer', class: 'healer',   baseLevel: 2, wagePerDay: 8,  description: 'A healer seeking safe passage to the northern lands.' },
    ];
  },

  /**
   * Show a brief toast notification inside the panel.
   * @param {string} msg
   * @param {'success'|'error'|'info'} [type='info']
   */
  _toast(msg, type = 'info') {
    const existing = this._el?.querySelector('.tmp-toast');
    existing?.remove();

    const t = document.createElement('div');
    t.className = 'tmp-toast';
    const color = type === 'success' ? '#4a8a30'
                : type === 'error'   ? '#8a3020'
                : '#3a5a80';
    t.style.cssText = `
      position:fixed;
      bottom:24px;
      left:50%;
      transform:translateX(-50%);
      background:${color};
      color:#f0f0e0;
      padding:10px 22px;
      border-radius:4px;
      font-family:Georgia,serif;
      font-size:0.88rem;
      z-index:260;
      pointer-events:none;
      box-shadow:0 3px 12px rgba(0,0,0,0.5);
      white-space:nowrap;
    `;
    t.textContent = msg;
    document.body.appendChild(t);
    setTimeout(() => t.remove(), 2400);
  },

  /** HTML-escape a string for safe innerHTML insertion. */
  _escHtml(str) {
    return String(str ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  },
};

export default TownMenuPanel;
