/**
 * QuestLogPanel — Quest log + fame badge overlay for Spellroads.
 *
 * Layout (desktop/tablet landscape):
 *   [QUEST LOG]  [Fame: Respected badge]  [Close]
 *   ────────────────────────────────────────────────
 *   [Quest List Sidebar] | [Quest Detail Pane]
 *
 * On mobile portrait the sidebar becomes a horizontal scrolling tab
 * row above the detail pane.
 *
 * Integrates with QuestSystem and FameSystem when available; falls back
 * to hardcoded placeholder data so the panel looks functional for testing.
 *
 * Opened/closed with `J` or `Escape`. Accessible via keyboard + gamepad.
 *
 * @module QuestLogPanel
 */

import { UIPanel } from './UIPanel.js';
import DebugLog from '../debug/DebugLog.js';
import EventBus from '../core/EventBus.js';

// ─── Style injection ──────────────────────────────────────────────────────────

const STYLE_ID = 'spellroads-questlog-style';

