// ─── Fame tier helpers ────────────────────────────────────────────────────────

/**
 * Maps a fame score (or tier name string) to display data.
 * @param {number|string} fameOrTier
 * @returns {{ tier: string, label: string, cssClass: string }}
 */
function resolveFameTier(fameOrTier) {
  const tierMap = {
    villain:   { label: 'Villain',    cssClass: 'fame-villain' },
    notorious: { label: 'Notorious',  cssClass: 'fame-notorious' },
    unknown:   { label: 'Unknown',    cssClass: 'fame-unknown' },
    known:     { label: 'Known',      cssClass: 'fame-known' },
    respected: { label: 'Respected',  cssClass: 'fame-respected' },
    legendary: { label: 'Legendary',  cssClass: 'fame-legendary' },
  };

  if (typeof fameOrTier === 'string' && tierMap[fameOrTier]) {
    return { tier: fameOrTier, ...tierMap[fameOrTier] };
  }

  // Numeric fame score
  const score = typeof fameOrTier === 'number' ? fameOrTier : 0;
  let tier;
  if      (score <= -500) tier = 'villain';
  else if (score < -100)  tier = 'notorious';
  else if (score <  100)  tier = 'unknown';
  else if (score <  300)  tier = 'known';
  else if (score <  700)  tier = 'respected';
  else                    tier = 'legendary';

  return { tier, ...tierMap[tier] };
}

