// ─── QuestLogPanel ────────────────────────────────────────────────────────────

class QuestLogPanel extends UIPanel {
  constructor() {
    injectStyles();
    super('panel-questlog', { trapFocus: false, zLayer: 'panel' });

    /** @type {string|null} Currently selected quest id */
    this._selectedId = null;

    /** @type {Array} Cached quest list from last open */
    this._quests = [];

    /** @type {Function|null} EventBus unsub handle */
    this._unsub = null;
  }

  // ─── UIPanel lifecycle ───────────────────────────────────────────────────

  show() {
    this._quests = this._loadQuests();

    // Auto-select first active quest (or first quest overall)
    const firstActive = this._quests.find(q => !q.completed);
    const firstAny    = this._quests[0];
    if (!this._selectedId || !this._quests.find(q => q.id === this._selectedId)) {
      this._selectedId = (firstActive ?? firstAny)?.id ?? null;
    }

    this._render();
    super.show();
    this._bindEvents();

    DebugLog.info('[quest] QuestLogPanel opened');
  }

  hide() {
    super.hide();
    DebugLog.info('[quest] QuestLogPanel closed');
  }

  destroy() {
    if (this._unsub) { this._unsub(); this._unsub = null; }
    super.destroy();
  }

  // ─── Data loading ────────────────────────────────────────────────────────

  /**
   * Load quests from QuestSystem if available, otherwise use placeholders.
   * @returns {Array}
   */
  _loadQuests() {
    try {
      // Dynamic import guard — QuestSystem may not be loaded yet
      const qs = window.__questSystem;
      if (qs && typeof qs.getActive === 'function') {
        const active    = qs.getActive() ?? [];
        const completed = (typeof qs.getCompleted === 'function' ? qs.getCompleted() : []) ?? [];
        const all       = [...active, ...completed];
        if (all.length > 0) return all;
      }
    } catch (e) {
      DebugLog.warn(`[quest] QuestSystem not available, using placeholders: ${e.message}`);
    }
    return PLACEHOLDER_QUESTS;
  }

  /**
   * Get current fame tier from FameSystem or return a default.
   * @returns {{ tier: string, label: string, cssClass: string }}
   */
  _loadFame() {
    try {
      const fs = window.__fameSystem;
      if (fs && typeof fs.getTier === 'function') {
        return resolveFameTier(fs.getTier());
      }
      if (fs && typeof fs.getFame === 'function') {
        return resolveFameTier(fs.getFame());
      }
    } catch (e) {
      DebugLog.warn(`[quest] FameSystem not available: ${e.message}`);
    }
    // Default fallback for testing
    return resolveFameTier('respected');
  }

  // ─── DOM build ───────────────────────────────────────────────────────────

  _buildHTML() {
    return `
      <div class="ql-header">
        <div class="ql-header-left">
          <div class="ql-title">Quest Log</div>
          <div class="ql-fame-badge fame-respected" id="ql-fame-badge">
            <span id="ql-fame-icon">&#9733;</span>
            <span id="ql-fame-label">Respected</span>
          </div>
        </div>
        <button class="ql-close" id="ql-close-btn" aria-label="Close quest log" tabindex="0">&times;</button>
      </div>
      <div class="ql-body">
        <nav class="ql-sidebar" id="ql-sidebar" role="navigation" aria-label="Quest list">
          <div id="ql-quest-list"></div>
        </nav>
        <div class="ql-detail" id="ql-detail" role="region" aria-label="Quest detail" aria-live="polite"></div>
      </div>
    `;
  }

  // ─── Full render ──────────────────────────────────────────────────────────

  _render() {
    this._renderFameBadge();
    this._renderQuestList();
    this._renderDetail();
  }

  // ─── Fame badge ───────────────────────────────────────────────────────────

  _renderFameBadge() {
    const badge     = this.el.querySelector('#ql-fame-badge');
    const labelEl   = this.el.querySelector('#ql-fame-label');
    if (!badge || !labelEl) return;

    const fame = this._loadFame();

    // Remove all tier classes and apply the current one
    badge.className = `ql-fame-badge ${fame.cssClass}`;
    labelEl.textContent = `Fame: ${fame.label}`;
  }

  // ─── Sidebar quest list ───────────────────────────────────────────────────

  _renderQuestList() {
    const list = this.el.querySelector('#ql-quest-list');
    if (!list) return;
    list.innerHTML = '';

    const active    = this._quests.filter(q => !q.completed);
    const completed = this._quests.filter(q => q.completed);

    if (this._quests.length === 0) {
      const empty = document.createElement('div');
      empty.className = 'ql-section-heading';
      empty.textContent = 'No active quests';
      list.appendChild(empty);
      return;
    }

    // Active section
    if (active.length > 0) {
      list.appendChild(this._makeSectionHeading(`Active (${active.length})`));
      list.appendChild(this._makeSectionDivider());
      for (const quest of active) {
        list.appendChild(this._makeQuestBtn(quest));
      }
    }

    // Completed section
    if (completed.length > 0) {
      list.appendChild(this._makeSectionHeading('Completed'));
      list.appendChild(this._makeSectionDivider());
      for (const quest of completed) {
        list.appendChild(this._makeQuestBtn(quest));
      }
    }
  }

  /**
   * @param {string} text
   * @returns {HTMLElement}
   */
  _makeSectionHeading(text) {
    const el = document.createElement('div');
    el.className = 'ql-section-heading';
    el.textContent = text;
    return el;
  }

  /**
   * @returns {HTMLElement}
   */
  _makeSectionDivider() {
    const el = document.createElement('div');
    el.className = 'ql-section-divider';
    return el;
  }

  /**
   * Build a sidebar quest button.
   * @param {object} quest
   * @returns {HTMLButtonElement}
   */
  _makeQuestBtn(quest) {
    const isActive = quest.id === this._selectedId;
    const btn = document.createElement('button');
    btn.className = [
      'ql-quest-btn',
      quest.completed ? 'completed' : '',
      isActive ? 'active' : '',
    ].filter(Boolean).join(' ');
    btn.dataset.questId = quest.id;
    btn.tabIndex = 0;
    btn.setAttribute('aria-pressed', isActive ? 'true' : 'false');
    btn.setAttribute('aria-label', quest.title);

    const nameEl = document.createElement('span');
    nameEl.className = 'ql-quest-btn-name';
    nameEl.textContent = quest.title;

    const locEl = document.createElement('span');
    locEl.className = 'ql-quest-btn-loc';
    locEl.textContent = quest.location ?? '';

    btn.appendChild(nameEl);
    if (quest.location) btn.appendChild(locEl);

    btn.addEventListener('click', () => this._selectQuest(quest.id));
    return btn;
  }

  // ─── Detail pane ──────────────────────────────────────────────────────────

  _renderDetail() {
    const pane = this.el.querySelector('#ql-detail');
    if (!pane) return;

    if (!this._selectedId) {
      pane.innerHTML = '<div class="ql-detail-empty">Select a quest to view details.</div>';
      return;
    }

    const quest = this._quests.find(q => q.id === this._selectedId);
    if (!quest) {
      pane.innerHTML = '<div class="ql-detail-empty">Quest not found.</div>';
      return;
    }

    // ── Title + meta ─────────────────────────────────────────────
    const titleEl = document.createElement('div');
    titleEl.className = 'ql-detail-title';
    titleEl.textContent = quest.title;

    const metaEl = document.createElement('div');
    metaEl.className = 'ql-detail-meta';

    const typeBadge = document.createElement('span');
    typeBadge.className = `ql-type-badge type-${quest.type ?? 'side'}`;
    typeBadge.textContent = this._typeLabel(quest.type);
    metaEl.appendChild(typeBadge);

    if (quest.location) {
      const locTag = document.createElement('span');
      locTag.className = 'ql-location-tag';
      locTag.textContent = quest.location;
      metaEl.appendChild(locTag);
    }

    // ── Description ──────────────────────────────────────────────
    const descEl = document.createElement('p');
    descEl.className = 'ql-description';
    descEl.textContent = quest.description ?? '';

    // ── Objectives ───────────────────────────────────────────────
    const objLabel = document.createElement('div');
    objLabel.className = 'ql-section-label';
    objLabel.textContent = 'Objectives';

    const objList = document.createElement('ul');
    objList.className = 'ql-objective-list';

    const objectives = quest.objectives ?? [];
    for (const obj of objectives) {
      objList.appendChild(this._makeObjectiveItem(obj));
    }

    if (objectives.length === 0) {
      const none = document.createElement('li');
      none.className = 'ql-objective-item';
      none.textContent = 'No objectives listed.';
      objList.appendChild(none);
    }

    // ── Rewards ──────────────────────────────────────────────────
    const rewardLabel = document.createElement('div');
    rewardLabel.className = 'ql-section-label';
    rewardLabel.textContent = 'Rewards';

    const rewardList = document.createElement('div');
    rewardList.className = 'ql-rewards-list';

    const rewards = quest.rewards ?? [];
    for (const reward of rewards) {
      rewardList.appendChild(this._makeRewardChip(reward));
    }

    if (rewards.length === 0) {
      const none = document.createElement('span');
      none.className = 'ql-reward-chip';
      none.textContent = 'None listed';
      rewardList.appendChild(none);
    }

    // ── Assemble ─────────────────────────────────────────────────
    pane.innerHTML = '';
    pane.appendChild(titleEl);
    pane.appendChild(metaEl);
    pane.appendChild(descEl);
    pane.appendChild(objLabel);
    pane.appendChild(objList);
    pane.appendChild(rewardLabel);
    pane.appendChild(rewardList);
  }

  /**
   * Build a single objective list item.
   * @param {{ text: string, current: number, total: number, done: boolean }} obj
   * @returns {HTMLLIElement}
   */
  _makeObjectiveItem(obj) {
    const li = document.createElement('li');
    li.className = `ql-objective-item${obj.done ? ' done' : ''}`;

    const icon = document.createElement('span');
    icon.className = 'ql-obj-icon';
    icon.setAttribute('aria-hidden', 'true');
    icon.textContent = obj.done ? '\u2713' : '\u25CB';

    const text = document.createElement('span');
    text.textContent = obj.text;

    li.appendChild(icon);
    li.appendChild(text);

    // Progress indicator (only when not a simple boolean completion)
    if (typeof obj.total === 'number' && obj.total > 1) {
      const prog = document.createElement('span');
      prog.className = 'ql-obj-progress';
      prog.textContent = `${obj.current ?? 0}/${obj.total}`;
      li.appendChild(prog);
    }

    return li;
  }

  /**
   * Build a single reward chip.
   * @param {{ icon: string, label: string }} reward
   * @returns {HTMLElement}
   */
  _makeRewardChip(reward) {
    const chip = document.createElement('span');
    chip.className = 'ql-reward-chip';

    const iconEl = document.createElement('span');
    iconEl.className = 'ql-reward-icon';
    iconEl.setAttribute('aria-hidden', 'true');
    iconEl.textContent = reward.icon ?? '';

    chip.appendChild(iconEl);
    chip.appendChild(document.createTextNode(reward.label ?? ''));
    return chip;
  }

  /**
   * Human-readable label for a quest type string.
   * @param {string} type
   * @returns {string}
   */
  _typeLabel(type) {
    const labels = {
      main:   'Main Quest',
      side:   'Side Quest',
      bounty: 'Bounty',
      errand: 'Errand',
    };
    return labels[type] ?? 'Quest';
  }

  // ─── Quest selection ──────────────────────────────────────────────────────

  /**
   * Select a quest by id, update sidebar highlights and re-render detail.
   * @param {string} questId
   */
  _selectQuest(questId) {
    this._selectedId = questId;

    // Update sidebar button states
    const buttons = this.el.querySelectorAll('.ql-quest-btn');
    for (const btn of buttons) {
      const isActive = btn.dataset.questId === questId;
      btn.classList.toggle('active', isActive);
      btn.setAttribute('aria-pressed', isActive ? 'true' : 'false');
    }

    this._renderDetail();

    DebugLog.info(`[quest] Selected quest: ${questId}`);
  }

  // ─── Event binding ────────────────────────────────────────────────────────

  _bindEvents() {
    // Close button
    const closeBtn = this.el.querySelector('#ql-close-btn');
    if (closeBtn && !closeBtn._qlBound) {
      closeBtn.addEventListener('click', () => this.hide());
      closeBtn._qlBound = true;
    }
  }

  // ─── Quest indicator helpers ──────────────────────────────────────────────

  /**
   * Add an animated '!' indicator badge to a map element.
   * Each questId gets its own badge; repeated calls for the same id are no-ops.
   *
   * @param {HTMLElement} mapElement — The element to attach the badge to
   * @param {string}      questId    — Unique quest identifier
   */
  static showQuestIndicator(mapElement, questId) {
    if (!mapElement) return;

    // Ensure the map element is positioned so the absolute badge renders correctly
    const pos = getComputedStyle(mapElement).position;
    if (pos === 'static') {
      mapElement.style.position = 'relative';
    }

    const existing = mapElement.querySelector(`[data-quest-indicator="${questId}"]`);
    if (existing) return; // Already attached

    const badge = document.createElement('span');
    badge.className = 'quest-indicator';
    badge.dataset.questIndicator = questId;
    badge.setAttribute('aria-label', 'Quest available');
    badge.setAttribute('aria-hidden', 'true');
    badge.textContent = '!';

    mapElement.appendChild(badge);
  }

  /**
   * Remove the '!' indicator badge for a specific questId from a map element.
   *
   * @param {HTMLElement} mapElement
   * @param {string}      questId
   */
  static hideQuestIndicator(mapElement, questId) {
    if (!mapElement) return;
    const badge = mapElement.querySelector(`[data-quest-indicator="${questId}"]`);
    if (badge) badge.remove();
  }

  // ─── Public init (singleton pattern) ─────────────────────────────────────

  /**
   * Initialize the panel and register EventBus listeners.
   * Call once from main.js.
   */
  init() {
    // Open when 'quest:open' is emitted (e.g. from debug console or other systems)
    this._unsub = EventBus.on('quest:open', () => {
      this.show();
    });

    DebugLog.info('[quest] QuestLogPanel initialized');
  }
}

// ─── Singleton export ─────────────────────────────────────────────────────────

const questLogPanel = new QuestLogPanel();
export default questLogPanel;
